#!/usr/bin/env bash
# tests/test_start_dry_run.sh — cco start --dry-run compose generation tests
#
# Verifies the docker-compose.yml generated by cmd_start --dry-run.
# No Docker daemon or running containers required.
# Dry-run writes all generated files to a temp dir ($DRY_RUN_DIR), NOT to the project directory.
# run_cco automatically extracts DRY_RUN_DIR from output.

# ── Basic generation ──────────────────────────────────────────────────

test_dry_run_creates_compose_file() {
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(minimal_project_yml test-proj)"
    run_cco start "test-proj" --dry-run
    assert_file_exists "$DRY_RUN_DIR/.cco/docker-compose.yml"
}

test_dry_run_no_persistent_artifacts() {
    # Dry-run must NOT write any files to the project directory
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(minimal_project_yml test-proj)"
    run_cco start "test-proj" --dry-run
    assert_file_not_exists "$CCO_PROJECTS_DIR/test-proj/.cco/docker-compose.yml"
    assert_file_not_exists "$CCO_PROJECTS_DIR/test-proj/.claude/workspace.yml"
    assert_file_not_exists "$CCO_PROJECTS_DIR/test-proj/.claude/packs.md"
}

test_dry_run_outputs_temp_dir_path() {
    # Dry-run must print the temp directory path in output
