# ── Volume mount ordering (Design Invariant 6) ───────────────────────

test_dry_run_volume_order_auth_before_global_config() {
    # Design Invariant 6: auth (.claude.json) before global config (settings.json)
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(minimal_project_yml test-proj)"
    run_cco start "test-proj" --dry-run
    local compose="$DRY_RUN_DIR/.cco/docker-compose.yml"
    local auth_line settings_line
    auth_line=$(grep -n ".claude.json:" "$compose" | head -1 | cut -d: -f1)
    settings_line=$(grep -n "settings.json:ro" "$compose" | head -1 | cut -d: -f1)
    if [[ -z "$auth_line" || -z "$settings_line" ]]; then
        echo "ASSERTION FAILED: could not find auth or settings line in compose"
        return 1
    fi
    if [[ "$auth_line" -ge "$settings_line" ]]; then
        echo "ASSERTION FAILED: auth (.claude.json) must appear before global settings.json"
        echo "  auth at line: $auth_line"
        echo "  settings at line: $settings_line"
        return 1
    fi
}

test_dry_run_volume_order_global_before_project() {
    # Design Invariant 6: global config before project config
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(minimal_project_yml test-proj)"
    run_cco start "test-proj" --dry-run
    local compose="$DRY_RUN_DIR/.cco/docker-compose.yml"
    local settings_line project_line
    settings_line=$(grep -n "settings.json:ro" "$compose" | head -1 | cut -d: -f1)
    project_line=$(grep -n "./.claude:/workspace/.claude" "$compose" | head -1 | cut -d: -f1)
    if [[ -z "$settings_line" || -z "$project_line" ]]; then
        echo "ASSERTION FAILED: could not find settings or project config line"
        return 1
    fi
    if [[ "$settings_line" -ge "$project_line" ]]; then
        echo "ASSERTION FAILED: global settings must appear before project .claude"
        echo "  settings at line: $settings_line"
        echo "  project at line: $project_line"
        return 1
    fi
}

test_dry_run_volume_order_memory_before_git() {
    # Design Invariant 6: claude-state mount before git mounts
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(minimal_project_yml test-proj)"
    run_cco start "test-proj" --dry-run
    local compose="$DRY_RUN_DIR/.cco/docker-compose.yml"
    local memory_line git_line
    memory_line=$(grep -n ".cco/claude-state.*-workspace" "$compose" | head -1 | cut -d: -f1)
    git_line=$(grep -n ".gitconfig:ro" "$compose" | head -1 | cut -d: -f1)
    if [[ -z "$memory_line" || -z "$git_line" ]]; then
        echo "ASSERTION FAILED: could not find memory or git line"
        return 1
    fi
    if [[ "$memory_line" -ge "$git_line" ]]; then
        echo "ASSERTION FAILED: memory must appear before git mounts"
        echo "  memory at line: $memory_line"
        echo "  git at line: $git_line"
        return 1
    fi
}

test_dry_run_volume_order_git_before_docker_socket() {
    # Design Invariant 6: git mounts before docker socket
    local tmpdir; tmpdir=$(mktemp -d); trap "rm -rf '$tmpdir'" EXIT
    setup_cco_env "$tmpdir"
    setup_global_from_defaults "$tmpdir"
    create_project "$tmpdir" "test-proj" "$(cat <<YAML
name: test-proj
description: "Test project"
