docker:
  mount_socket: true
  ports: []
  env: {}
repos:
  - path: $CCO_DUMMY_REPO
    name: dummy-repo
YAML
)"
    run_cco start "test-proj" --dry-run
    local compose="$DRY_RUN_DIR/.cco/docker-compose.yml"
    local git_line socket_line
    git_line=$(grep -n ".gitconfig:ro" "$compose" | head -1 | cut -d: -f1)
    socket_line=$(grep -n "docker.sock" "$compose" | head -1 | cut -d: -f1)
    if [[ -z "$git_line" || -z "$socket_line" ]]; then
        echo "ASSERTION FAILED: could not find git or docker socket line"
        return 1
    fi
    if [[ "$git_line" -ge "$socket_line" ]]; then
        echo "ASSERTION FAILED: git mounts must appear before docker socket"
        echo "  git at line: $git_line"
        echo "  socket at line: $socket_line"
        return 1
    fi
}

